using System.Text.Json;
using ModelContextProtocol;

[McpToolType]
public static class WeatherTools
{
    [McpTool("get_weather", Description = "Get current weather for a location by latitude and longitude.")]
    public static async Task<string> GetWeather(
        IHttpClientFactory httpClientFactory,
        [McpParameter(Description = "Latitude of the location")] double latitude,
        [McpParameter(Description = "Longitude of the location")] double longitude)
    {
        var client = httpClientFactory.CreateClient("WeatherApi");

        var url = $"v1/forecast?latitude={latitude}&longitude={longitude}&current_weather=true";
        var response = await client.GetAsync(url);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadFromJsonAsync<JsonElement>();
        var weather = json.GetProperty("current_weather");

        return $"Temperature: {weather.GetProperty("temperature")}°C, " +
               $"Wind: {weather.GetProperty("windspeed")} km/h, " +
               $"Direction: {weather.GetProperty("winddirection")}°";
    }

    [McpTool("get_location_name", Description = "Search for a location and return its coordinates.")]
    public static async Task<string> GetLocationName(
        IHttpClientFactory httpClientFactory,
        [McpParameter(Description = "Name of the city or place to search")] string name)
    {
        var client = httpClientFactory.CreateClient("WeatherApi");

        var url = $"v1/search?name={Uri.EscapeDataString(name)}&count=1";
        var response = await client.GetAsync(url);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadFromJsonAsync<JsonElement>();

        if (!json.TryGetProperty("results", out var results) || results.GetArrayLength() == 0)
            return "Location not found.";

        var loc = results[0];
        return $"{loc.GetProperty("name")}: lat={loc.GetProperty("latitude")}, lon={loc.GetProperty("longitude")}";
    }
}

